import React, { useEffect, useState } from "react";
import axios from "axios";

function Charts() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get("http://127.0.0.1:8000/history?symbol=BTC&limit=10")
      .then((res) => {
        setData(res.data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <p>Loading...</p>;

  if (!data || data.length < 2) {
    return <p>Not enough data for chart (run /fetch multiple times)</p>;
  }

  return (
    <div>
      <h3>BTC Price Chart</h3>
      <ul>
        {data.map((item, index) => (
          <li key={index}>
            {new Date(item.timestamp).toLocaleTimeString()} → ${item.price}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Charts;
